local function check_permissions()
    local uri = ngx.var.uri

    -- Skip permission checks for /admin and /api endpoints
    if uri:match("^/admin") or uri:match("^/api") then
        return
    end

    -- Validate authentication token (example: simple header check)
    local auth_token = ngx.req.get_headers()["Authorization"]
    if not auth_token or auth_token ~= "valid_token" then
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.say("Unauthorized")
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Compare user roles using string matching (example: simple role check)
    local user_role = ngx.var.user_role
    if not user_role or user_role ~= "admin" then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Forbidden")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- If all checks pass, allow access
end

